scwin.btn_send_onclick = function (e) {
  let saveCnt = 0;
  for (var i = 0; i < ds_Regist.getRowCount(); i++) {
    if (ds_Regist.getCellData(i, "chk") == 1) {
      ds_Regist.setCellData(i, "chk", 0);
      if (ds_Regist.getRowStatus(i) == 3) {
        ds_Regist.setCellData(i, "chk", 1);
        ds_Regist.setRowPosition(i);
        $c.gus.cfAlertMsg($p, "변경된 반출통고목록이 있습니다.\n먼저 저장하시기 바랍니다.");
        for (var j = 0; j < ds_Regist.getRowCount(); j++) {
          ds_Regist.setCellData(j, "chk", 0);
          if (ds_Regist.getRowStatus(j) == 3) {
            ds_Regist.setCellData(j, "chk", 1);
          }
        }
        $c.gus.cfDisableObjects($p, [btn_print, btn_send]);
        $c.gus.cfEnableObjects($p, [btn_delete, btn_save, tbl_master]);
        return;
      }
      ds_Regist.setCellData(i, "chk", 1);
      saveCnt++;
    }
  }
  if (saveCnt == 0) {
    $c.gus.cfAlertMsg($p, "선택된 반출통고목록이 없습니다.");
    return;
  }
  for (var i = 0; i < ds_Regist.getRowCount(); i++) {
    if (ds_Regist.getCellData(i, "chk") == 1) {
      ds_Regist.setCellData(i, "procClsCd", "0");
      ds_Regist.setCellData(i, "procClsNm", "전송대기");
    }
  }
  $c.sbm.execute($p, sbm_send);
};

