// 공통 팝업 호출 (case별 UDC/코드/명 매핑)
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  switch (disGubun) {
    case 1:
      // 선박
      udc_vssl.cfCommonPopUp(scwin.f_popupCallback(1), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
      break;
    case 2:
      // 화주상호
      udc_clntNo.cfCommonPopUp(scwin.f_popupCallback(2), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
      break;
    case 3:
      // 신고세관
      udc_cstm.cfCommonPopUp(scwin.f_popupCallback(3), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
      break;
    case 4:
      // 신고과
      udc_cstmSec.cfCommonPopUp(scwin.f_popupCallback(4), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
      break;
  }
};

// 공통 팝업 콜백
scwin.f_popupCallback = function (disGubun) {
  return function (rtnList) {
    switch (disGubun) {
      case 1:
        // 선박
        cfSetReturnValue(rtnList, ed_vsslCd, txt_vsslNm);
        break;
      case 2:
        // 화주상호
        cfSetReturnValue(rtnList, ed_clntNo, txt_mchtNmCmpy);
        break;
      case 3:
        // 신고세관
        cfSetReturnValue(rtnList, ed_cstmCd, txt_cstmNm);
        break;
      case 4:
        // 신고과
        cfSetReturnValue(rtnList, ed_cstmSecCd, txt_cstmSecNm);
        break;
    }
  };
};

// 팝업 리턴값 세팅
function cfSetReturnValue(rtnList, codeObj, nameObj) {
  if (rtnList != null && rtnList[0] != "N/A") {
    codeObj.setValue(rtnList[0]);
    nameObj.setValue(rtnList[1]);
  }
}

